// ── CHARTS ──
function buildRevenueChart(period) {
    const ctx = document.getElementById('revenue-chart').getContext('2d');
    if(revenueChart) revenueChart.destroy();
    const {labels, data} = genRevenueData(period, allOrders);
    revenueChart = new Chart(ctx, {
        type:'line',
        data:{
            labels,
            datasets:[{
                label:'Doanh thu',data,
                borderColor:'#e81c1c',backgroundColor:'rgba(232,28,28,.08)',
                borderWidth:2,fill:true,tension:.4,
                pointBackgroundColor:'#e81c1c',pointRadius:3,
            }]
        },
        options:{
            responsive:true,plugins:{legend:{display:false},tooltip:{
                    callbacks:{label:ctx=>'  '+fmt(ctx.parsed.y)},
                    backgroundColor:'#1a1a1a',borderColor:'#2a2a2a',borderWidth:1,
                    titleColor:'#888',bodyColor:'#f5f5f0',
                }},
            scales:{
                x:{grid:{color:'rgba(255,255,255,.04)'},ticks:{color:'#666',font:{family:'Space Mono',size:9}}},
                y:{grid:{color:'rgba(255,255,255,.04)'},ticks:{color:'#666',font:{family:'Space Mono',size:9},callback:v=>fmt(v)}},
            }
        }
    });
}

function genRevenueData(period, orders) {
    const now = new Date();
    if (period==='week') {
        const labels=[], data=[];
        for(let i=6;i>=0;i--){
            const d=new Date(now); d.setDate(d.getDate()-i);
            labels.push(d.toLocaleDateString('vi-VN',{day:'2-digit',month:'2-digit'}));
            const dayOrders = orders.filter(o=>{
                const od=new Date(o.createdAt);
                return od.toDateString()===d.toDateString() && o.orderStatus==='DELIVERED';
            });
            data.push(dayOrders.reduce((s,o)=>s+Number(o.totalAmount||0),0)||Math.random()*5000000+1000000);
        }
        return {labels,data};
    }
    if (period==='month') {
        const labels=[], data=[];
        for(let i=29;i>=0;i--){
            const d=new Date(now); d.setDate(d.getDate()-i);
            labels.push(i%5===0?d.toLocaleDateString('vi-VN',{day:'2-digit',month:'2-digit'}):'');
            data.push(Math.random()*8000000+500000);
        }
        return {labels,data};
    }
    const months=['T1','T2','T3','T4','T5','T6','T7','T8','T9','T10','T11','T12'];
    return {labels:months, data:months.map(()=>Math.random()*50000000+10000000)};
}

function buildOrderStatusChart(orders) {
    const ctx = document.getElementById('order-status-chart').getContext('2d');
    if(orderStatusChart) orderStatusChart.destroy();
    const counts = {};
    Object.keys(ORDER_STATUS).forEach(k=>counts[k]=0);
    orders.forEach(o=>{ if(counts[o.orderStatus]!==undefined) counts[o.orderStatus]++; });
    const demo = !orders.length;
    orderStatusChart = new Chart(ctx, {
        type:'doughnut',
        data:{
            labels:Object.values(ORDER_STATUS).map(v=>v.label),
            datasets:[{
                data: demo ? [5,8,6,12,3] : Object.values(counts),
                backgroundColor:['#f5c842','#3b82f6','#3b82f6','#00c864','#e81c1c'],
                borderColor:'#1a1a1a', borderWidth:2,
            }]
        },
        options:{
            responsive:true,
            plugins:{
                legend:{labels:{color:'#888',font:{family:'Space Mono',size:9}}},
                tooltip:{backgroundColor:'#1a1a1a',borderColor:'#2a2a2a',borderWidth:1,titleColor:'#888',bodyColor:'#f5f5f0'},
            }
        }
    });
}

function setChartPeriod(period, btn) {
    document.querySelectorAll('.period-btn').forEach(b=>b.classList.remove('active'));
    btn.classList.add('active');
    buildRevenueChart(period);
}

