async function loadUsers() {
    try {
        const res = await apiFetch('/admin/users');
        allUsers = res?.result ?? res ?? [];
        if(!Array.isArray(allUsers)) allUsers=[];
    } catch(e) { allUsers=[]; }
    renderUsers();
}

function filterUsers() { currentPage.users=1; renderUsers(); }

function renderUsers() {
    const search = document.getElementById('user-search')?.value.toLowerCase()||'';
    const filter = document.getElementById('user-filter')?.value||'';
    let filtered = allUsers.filter(u=>{
        const match = !search || (u.name||'').toLowerCase().includes(search)
            || (u.username||'').toLowerCase().includes(search)
            || (u.email||'').toLowerCase().includes(search);
        const statusMatch = !filter ||
            (filter==='active' && u.isActive) ||
            (filter==='inactive' && !u.isActive);
        return match && statusMatch;
    });
    const total=filtered.length, page=currentPage.users;
    const paged=filtered.slice((page-1)*PAGE_SIZE, page*PAGE_SIZE);
    const body=document.getElementById('users-body');
    if(!paged.length){body.innerHTML='<tr><td colspan="8" class="tbl-empty">KHÔNG CÓ DỮ LIỆU</td></tr>';return;}
    body.innerHTML=paged.map((u,i)=>`<tr>
    <td style="color:var(--grey-light);font-family:var(--font-mono);font-size:11px">${(page-1)*PAGE_SIZE+i+1}</td>
    <td>${u.name||'—'}</td>
    <td style="font-family:var(--font-mono);font-size:12px">${u.username||'—'}</td>
    <td style="color:var(--grey-light)">${u.email||'—'}</td>
    <td style="font-family:var(--font-mono);font-size:12px">${u.phone||'—'}</td>
    <td><span class="badge ${u.isActive?'badge-green':'badge-red'}">${u.isActive?'Hoạt động':'Bị khóa'}</span></td>
    <td style="font-family:var(--font-mono);font-size:11px;color:var(--grey-light)">${fmtDate(u.createdAt)}</td>
    <td>
      <button class="tbl-action" onclick="viewUser('${u.id}')">Chi tiết</button>
      <button class="tbl-action ${u.isActive?'danger':'success'}" onclick="toggleUser('${u.id}',${u.isActive})">
        ${u.isActive?'Khoá':'Mở'}
      </button>
    </td>
  </tr>`).join('');
    renderPagination('users', total, page);
}

function viewUser(id) {
    const u = allUsers.find(x=>x.id===id); if(!u) return;
    document.getElementById('user-detail-body').innerHTML=`
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px">
      ${[['Họ tên',u.name],['Username',u.username],['Email',u.email],
            ['Điện thoại',u.phone],['Ngày sinh',fmtDate(u.dob)],['Giới tính',u.gender],
            ['Trạng thái',u.isActive?'✓ Hoạt động':'✕ Bị khóa'],['Ngày tạo',fmtDateTime(u.createdAt)],
        ].map(([k,v])=>`
        <div style="background:var(--black);padding:12px;border:1px solid var(--grey-border)">
          <div style="font-family:var(--font-mono);font-size:9px;letter-spacing:2px;color:var(--grey-light);margin-bottom:4px">${k}</div>
          <div style="font-size:13px">${v||'—'}</div>
        </div>`).join('')}
    </div>`;
    document.getElementById('user-detail-footer').innerHTML=`
    <button class="btn btn-secondary" onclick="closeModal('modal-user')">Đóng</button>
    <button class="btn ${u.isActive?'btn-danger':'btn-success'}" onclick="toggleUser('${u.id}',${u.isActive});closeModal('modal-user')">
      ${u.isActive?'Khoá tài khoản':'Mở tài khoản'}
    </button>`;
    openModal('modal-user');
}

async function toggleUser(id, isActive) {
    confirm2('Xác nhận', `${isActive?'Khoá':'Mở'} tài khoản người dùng này?`, async()=>{
        try {
            await apiFetch(`/admin/users/${id}/${isActive?'deactivate':'activate'}`, {method:'PATCH'});
            showToast(`Đã ${isActive?'khoá':'mở'} tài khoản`);
            await loadUsers();
        } catch(e) {
            const u=allUsers.find(x=>x.id===id);
            if(u) u.isActive=!isActive;
            renderUsers();
            showToast(`Đã ${isActive?'khoá':'mở'} tài khoản (demo)`);
        }
    });
}

